# ------------------------------------------------------------------------------
#' @title Map colors to pathway nodes
#'
#' @description This function generates a data frame that can be used to map
#' colors onto the pathway diagram.
#' @param nodes_df A data frame with node information, as generated by the
#' .prepareNodes() function.
#' @param annGenes (optional) \code{character} string of the Bioconductor
#' annotation package (e.g., org.Hs.eg.db).
#' @param annMetabolites (optional) \code{tibble} or \code{data.frame} with
#' metabolite mapping information (see metaboliteIDmapping package).
#' @param inputDB Input gene ID type (SYMBOL, ENTREZID, ENSEMBL, UNIPROT).
#' @param featureIDs Vector of gene IDs.
#' @param colorVar Vector or data frame with the variables used for coloring.
#' The order should match Gene IDs.
#' @param colorList A list with information about the coloring of the nodes.
#' An example can be generated using the defaultColorList() function.
#' @param NAvalue Node color for NA color values.
#' @return A data frame used for plotting colored nodes.
#' @noRd

.mapColors <- function(
        nodes_df,
        annGenes,
        annMetabolites,
        inputDB,
        featureIDs,
        colorVar,
        colorList,
        NAvalue){

    # Get gene/protein/metabolite IDs of all nodes
    featureIDs_nodes <- nodes_df[,c("Database", "ID", "GraphId1")]

    # Perform gene and metabolite mapping
    nodeAnn_all <- rbind.data.frame(
        .geneMapping(featureIDs_nodes, annGenes, inputDB, featureIDs, colorVar),
        .metaboliteMapping(
            featureIDs_nodes, annMetabolites, inputDB, featureIDs, colorVar))

    # Add node annotation to the node graphical elements
    colors_df <- dplyr::left_join(nodes_df, nodeAnn_all, by = "GraphId1")

    # If one node has at least 1 non-NA color value,
    # remove the NA values from different inputIds:
    colors_df <- .removeNAnodes(colors_df)

    # If there are duplicated IDs, split the node into two parts for coloring
    colors_df <- .splitNode(colors_df)

    # Add color values to data frame
    colors_df <- .addColor(colors_df, colorList, NAvalue)

    # Return data frame
    return(colors_df)
}


.geneMapping <- function(
        featureIDs_nodes, annGenes, inputDB, featureIDs, colorVar){

    geneDBs_GPML <- c("Ensembl", "Entrez Gene", "Uniprot-TrEMBL", "HGNC")
    geneDBs_all <- AnnotationDbi::columns(get(
        annGenes, envir = asNamespace(annGenes)))
    featureIDs_fil <- featureIDs_nodes[
        featureIDs_nodes$Database %in% geneDBs_GPML,]

    if (nrow(featureIDs_fil)==0){return(NULL)}else{
        # Convert name of database
        featureIDs_fil$Database <- .convertDBname(featureIDs_fil$Database)

        # Convert gene IDs of the nodes to the input IDs
        nodeAnn_gene <- NULL
        for (db in unique(inputDB[inputDB %in% geneDBs_all])){
            if (is.data.frame(colorVar)){
                input <- NULL
                for (i in seq_len(ncol(colorVar))){
                    input <- rbind(
                        input, data.frame(
                            GeneID = featureIDs[inputDB == db],
                            Col = colorVar[inputDB == db,i],
                            Scale = i, ScaleName = colnames(colorVar)[i]))}
            } else{
                input <- data.frame(
                    GeneID = featureIDs[inputDB == db],
                    Col = colorVar[inputDB == db],
                    Scale = 1,ScaleName = "Color")}

            # Convert node IDs
            nodeAnn <- .geneAnnotation(featureIDs_fil, db, annGenes)

            # Combine node annotation with input
            nodeAnn <- dplyr::left_join(
                nodeAnn, input, by = c("InputId" = "GeneID"),
                relationship = "many-to-many")

            # Change column names
            nodeAnn <- nodeAnn[,c(
                "GraphId1","InputId","Col","Scale","ScaleName")]
            colnames(nodeAnn) <- c(
                "GraphId1","InputId","MapColor","Scale","ScaleName")
            nodeAnn_gene <- rbind.data.frame(nodeAnn_gene, nodeAnn)
        }
        return(nodeAnn_gene)
    }
}

.convertDBname <- function(DBname){
    DBname <- replace(
        DBname,
        DBname == "Ensembl",
        "ENSEMBL")
    DBname <- replace(
        DBname,
        DBname == "Entrez Gene",
        "ENTREZID")
    DBname <- replace(
        DBname,
        DBname == "Uniprot-TrEMBL",
        "UNIPROT")
    DBname <- replace(
        DBname,
        DBname == "HGNC",
        "SYMBOL")
    return(DBname)
}

.geneAnnotation <- function(featureIDs_fil, db, annGenes){
    databases_GPML <- unique(featureIDs_fil$Database)
    nodeAnn <- NULL

    for (i in seq_along(databases_GPML)){
        keytype <- databases_GPML[i]

        # If gene IDs are already the same as the input IDs
        if (keytype == db){
            temp <- featureIDs_fil[featureIDs_fil$Database == keytype, ]
            temp$InputId <- temp$ID
            temp <- unique(temp[,c("GraphId1", "InputId")])

            # If gene IDs are different from input IDs
        }else{
            temp <- tryCatch({
                temp <- featureIDs_fil[featureIDs_fil$Database == keytype, ]
                ann <- withCallingHandlers(
                    AnnotationDbi::select(BiocGenerics::get(
                        annGenes, envir = asNamespace(annGenes)),
                        columns = c(keytype, db),
                        keys = temp$ID,
                        keytype = keytype),
                    message = function(m){
                        if (grepl("many mapping",conditionMessage(m))){
                            invokeRestart("muffleMessage")
                        }
                    }
                )
                temp <- dplyr::left_join(
                    temp, ann,
                    by = c("ID" = keytype),
                    relationship = "many-to-many")
                colnames(temp) <- c("Database","ID","GraphId1","InputId")
                temp <- unique(temp[,c("GraphId1", "InputId")])
                temp
            }, error = function(cond){NULL})
        }
        nodeAnn <- rbind.data.frame(nodeAnn, temp)
    }
    nodeAnn <- nodeAnn[!duplicated(nodeAnn),]
    nodeAnn <- nodeAnn[!is.na(nodeAnn$InputId),]
    return(nodeAnn)
}

.metaboliteMapping <- function(
        featureIDs_nodes, annMetabolites, inputDB, featureIDs, colorVar){
    metaboliteDBs <- c("HMDB", "CAS", "ChEBI")
    metaboliteDBs_name <- colnames(annMetabolites)
    featureIDs_fil <- featureIDs_nodes[
        featureIDs_nodes$Database %in% metaboliteDBs,]

    if (nrow(featureIDs_fil)==0){return(NULL)}else{
        # Convert metabolite IDs of the nodes to the input IDs
        databases_GPML <- unique(featureIDs_fil$Database)
        nodeAnn_metabolite <- NULL
        for (db in unique(inputDB[inputDB %in% metaboliteDBs_name])){
            if (is.data.frame(colorVar)){
                input <- NULL
                for (i in seq_len(ncol(colorVar))){
                    input <- rbind(
                        input,
                        data.frame(
                            GeneID = featureIDs[inputDB == db],
                            Col = colorVar[inputDB == db,i],
                            Scale = i,
                            ScaleName = colnames(colorVar)[i]
                        ))
                }
            } else{
                input <- data.frame(
                    GeneID = featureIDs[inputDB == db],
                    Col = colorVar[inputDB == db],
                    Scale = 1, ScaleName = "Color")
            }
            # Convert node IDs
            nodeAnn <- .metaboliteAnnotation(featureIDs_fil,db,annMetabolites)

            # Combine node annotation with input
            nodeAnn <- dplyr::left_join(
                nodeAnn, input,
                by = c("InputId" = "GeneID"),
                relationship = "many-to-many")

            # Change column names
            nodeAnn <- nodeAnn[,c(
                "GraphId1","InputId","Col","Scale","ScaleName")]
            colnames(nodeAnn) <- c(
                "GraphId1","InputId","MapColor", "Scale", "ScaleName")
            nodeAnn_metabolite <- rbind.data.frame(nodeAnn_metabolite, nodeAnn)
        }
        return(nodeAnn_metabolite)
    }
}

.metaboliteAnnotation<- function(featureIDs_fil, db, annMetabolites){
    databases_GPML <- unique(featureIDs_fil$Database)
    nodeAnn <- NULL
    for (i in seq_along(databases_GPML)){
        keytype <- databases_GPML[i]

        # If gene IDs are already the same as the input IDs
        if (keytype == db){
            temp <- featureIDs_fil[featureIDs_fil$Database == keytype, ]
            temp$InputId <- temp$ID
            temp <- unique(temp[,c("GraphId1", "InputId")])

            # If gene IDs are different from input IDs
        }else{
            temp <- tryCatch({
                temp <- featureIDs_fil[featureIDs_fil$Database == keytype, ]
                ann <- annMetabolites[
                    annMetabolites[,keytype] %in% temp$ID,c(keytype, db)]
                ann <- ann[!(is.na(ann[,1]) | is.na(ann[,2])),]
                temp <- dplyr::left_join(
                    temp, ann, by = c("ID" = keytype),
                    relationship = "many-to-many")
                colnames(temp) <- c("Database", "ID", "GraphId1", "InputId")
                temp <- unique(temp[,c("GraphId1", "InputId")])
                temp
            }, error = function(cond){NULL})
        }
        nodeAnn <- rbind.data.frame(nodeAnn, temp)
    }
    nodeAnn <- nodeAnn[!duplicated(nodeAnn),]
    nodeAnn <- nodeAnn[!is.na(nodeAnn$InputId),]
    return(nodeAnn)
}

.splitNode <- function(colors_df){
    dupIds <- unique(colors_df$GraphId1[(duplicated(colors_df$GraphId1))])
    if (length(dupIds) > 0){
        for (d in seq_along(dupIds)){
            temp <- colors_df[colors_df$GraphId1 == dupIds[d],]
            newWidth <- temp$Width/nrow(temp)
            newCenterX <- temp$CenterX - (0.5*(nrow(temp)-1))*newWidth +
                (0.5+seq(0,nrow(temp)-1,1)*newWidth)

            colors_df$Width[colors_df$GraphId1 == dupIds[d]] <- newWidth
            colors_df$CenterX[colors_df$GraphId1 == dupIds[d]] <- newCenterX

        }
    }
    return(colors_df)
}

.removeNAnodes <- function(colors_df){
    # Nodes with non-NA values
    nonNA_nodes <- colors_df$GraphId1[!is.na(colors_df$MapColor)]

    # all node-id combinations
    node_ids <- paste0(
        colors_df$InputId[colors_df$GraphId1 %in% nonNA_nodes],
        "_",
        colors_df$GraphId1[colors_df$GraphId1 %in% nonNA_nodes])

    # Node-id combinations with NA values
    NAids <- node_ids[
        is.na(colors_df$MapColor[colors_df$GraphId1 %in% nonNA_nodes])]

    # Node-id combinations with non-NA values
    nonNAids <- node_ids[
        !is.na(colors_df$MapColor[colors_df$GraphId1 %in% nonNA_nodes])]

    # Remove Node-Ids with only NA values
    rmIds <- setdiff(NAids, nonNAids)
    colors_df <- colors_df[!(paste0(
        colors_df$InputId,
        "_",
        colors_df$GraphId1) %in% rmIds),]
    return(colors_df)
}
# ------------------------------------------------------------------------------
#' @title Match colors codes with color values
#'
#' @description This function generates a data frame that can be used to map
#' colors onto the pathway diagram.
#' @param colors_df A data frame with values for coloring added to the nodes.
#' @param colorList A list with information about the coloring of the nodes.
#' @param NAvalue Node color for NA color values.
#' @return A data frame used for mapping colors onto the pathway diagram.
#' @noRd

.addColor <- function(colors_df, colorList, NAvalue = "#F0F0F0"){

    # Add NA as default color value
    colors_df$ColorValue <- NA

    # Set NA scales to NA color
    plot_df_NA <- NULL
    if (sum(is.na(colors_df$Scale)) > 0){
        plot_df_NA <- colors_df[is.na(colors_df$Scale),]
        plot_df_NA$ColorValue <- NAvalue
    }

    # Get the unique color scales
    scales <- unique(colors_df$Scale)
    scales <- scales[!is.na(scales)]

    # For each scale, we are going to add the color
    plot_df_scale <- NULL
    if (length(scales) > 0){
        for (s in seq_along(scales)){
            ScaleType <- colorList[[s]]$ScaleType

            if (ScaleType == "Divergent"){
                plot_df <- .addDivergent(colors_df, scales, colorList, s)}

            if (ScaleType == "Sequential"){
                plot_df <- .addSequential(colors_df, scales, colorList, s)}

            if (ScaleType == "Qualitative"){
                plot_df <- .addQualitative(colors_df, scales, colorList, s)}

            # Combine the data from different scales
            plot_df_scale <- rbind.data.frame(plot_df_scale, plot_df)
        }
    }
    # Combine the data from the scales with the NA values
    plot_df_all <- rbind.data.frame(plot_df_scale, plot_df_NA)
    return(plot_df_all)
}

.addDivergent <- function(colors_df, scales, colorList, s){
    # Make map color numeric
    plot_df <- colors_df[colors_df$Scale == scales[s],]
    plot_df <- plot_df[!is.na(plot_df$Scale),]
    plot_df$MapColor <- as.numeric(plot_df$MapColor)

    # Make color gradient from middle to max value
    pal_up <- grDevices::colorRampPalette(
        colors = c(
            colorList[[s]]$Color["MidCol"],
            colorList[[s]]$Color["MaxCol"]))(101)

    # Make color gradient from min to middle value
    pal_down <- grDevices::colorRampPalette(
        colors = c(
            colorList[[s]]$Color["MidCol"],
            colorList[[s]]$Color["MinCol"]))(101)

    # Get color scale values
    midvalue <- as.numeric(colorList[[s]]$ColorVal["MidVal"])
    minvalue <-  as.numeric(colorList[[s]]$ColorVal["MinVal"])
    maxvalue <-  as.numeric(colorList[[s]]$ColorVal["MaxVal"])


    # Set up values
    plot_df_up <- plot_df[plot_df$MapColor >= midvalue,]
    col_index <- round(
        (plot_df_up$MapColor - midvalue)/
            (maxvalue - midvalue)*100,0
    ) + 1
    col_index[col_index>100] <- 100
    plot_df_up$ColorValue <- pal_up[col_index]


    # Set down values
    plot_df_down <- plot_df[plot_df$MapColor < midvalue,]
    col_index <- round(
        (plot_df_down$MapColor - midvalue)/
            (minvalue - midvalue)*100,0
    ) + 1
    col_index[col_index>100] <- 100
    plot_df_down$ColorValue <- pal_down[col_index]

    # combine up and down values
    plot_df <- rbind.data.frame(plot_df_up, plot_df_down)
    return(plot_df)
}


.addSequential <- function(colors_df, scales, colorList, s){
    # Make map color numeric
    plot_df <- colors_df[colors_df$Scale == scales[s],]
    plot_df <- plot_df[!is.na(plot_df$Scale),]
    plot_df$MapColor <- as.numeric(plot_df$MapColor)

    # Make color gradient from middle to max value
    pal <- grDevices::colorRampPalette(
        colors = c(
            colorList[[s]]$Color["MinCol"],
            colorList[[s]]$Color["MaxCol"]))(101)


    # Get color scale values
    minvalue <-  as.numeric(colorList[[s]]$ColorVal["MinVal"])
    maxvalue <-  as.numeric(colorList[[s]]$ColorVal["MaxVal"])

    # Set color values
    col_index <- round(
        (plot_df$MapColor - minvalue)/
            (maxvalue - minvalue)*100,0
    ) + 1
    col_index[col_index>100] <- 100
    col_index[col_index<1] <- 1
    plot_df$ColorValue <- pal[col_index]
    return(plot_df)
}

.addQualitative <- function(colors_df, scales, colorList, s){
    plot_df <- colors_df[colors_df$Scale == scales[s],]
    plot_df <- plot_df[!is.na(plot_df$Scale),]
    plot_df$ColorValue <- colorList[[s]]$Color[plot_df$MapColor]
    return(plot_df)
}

# ------------------------------------------------------------------------------
#' @title Draw colors
#'
#' @description This function add node colors to the pathway image.
#' @param colors_df A data frame with edge information, as generated by the
#' .mapColors() function.
#' @return A plot with colored nodes.
#' @noRd

.drawColors <- function(colors_df) {

    graphics::rect(
        xleft = colors_df$CenterX - 0.5 * colors_df$Width,
        ybottom = -1 * (colors_df$CenterY - 0.5 * colors_df$Height),
        xright =  colors_df$CenterX + 0.5 * colors_df$Width,
        ytop =  -1 * (colors_df$CenterY + 0.5 * colors_df$Height),
        col = colors_df$ColorValue,
        border = NA,
        lty = colors_df$LineStyle,
        lwd = colors_df$LineThickness
    )

}


# ------------------------------------------------------------------------------
#' @title Make legend
#'
#' @description This function makes legend for the pathway image.
#' @param colorList A list with information about the coloring of the nodes.
#' An example can be generated using the defaultColorList() function.
#' @return A legend for the node colors.
#' @noRd

.makeLegend <- function(colorList){

    # Default settings
    nScales <- length(colorList)
    width <- 1
    height <- 0.5

    # Make empty canvas
    graphics::par(mar = c(1,1,1,1))
    plot(c(0,2), c(-nScales-0.25,1), col = "white", axes = FALSE, ann = FALSE)
    vps <- gridBase::baseViewports()
    grid::pushViewport(vps$inner, vps$figure, vps$plot)
    grid::grid.rect(
        x = seq(1/(2*nScales),1-(1/(2*nScales)),1/nScales), y = 0.5,
        width = width/nScales, height = height,
        default.units = "native", gp = grid::gpar(col = "black"))

    # Add color scales
    for (s in seq_len(nScales)){
        ScaleType <- colorList[[s]]$ScaleType
        if (ScaleType == "Divergent"){.legendDivergent(colorList, s)}
        if (ScaleType == "Sequential"){.legendSequential(colorList, s)}
        if (ScaleType == "Qualitative"){.legendQualitative(colorList, s)}
    }
}


.legendDivergent <- function(colorList, s){
    nScales <- length(colorList)
    width <- 1
    height <- 0.5

    minVal <- colorList[[s]]$ColorVal["MinVal"]
    midVal <- colorList[[s]]$ColorVal["MidVal"]
    maxVal <- colorList[[s]]$ColorVal["MaxVal"]
    pal <- grDevices::colorRampPalette(
        colors = c(
            colorList[[s]]$Color["MinCol"],
            colorList[[s]]$Color["MidCol"],
            colorList[[s]]$Color["MaxCol"]))

    graphics::text(
        x = 1.5, y = (s-1)-nScales + 0.5*height,
        labels = colorList[[s]]$ScaleName, pos = 3, font = 2)
    grid::grid.rect(
        x = seq(0.1,0.9,length = 81*2) + 1, y = (s-1)-nScales,
        width = 0.01/2, height = height, default.units = "native",
        gp = grid::gpar(col = NA, fill = pal(81*2)))
    graphics::arrows(
        x0 = 1/(2*nScales) + (s-1)*1/nScales,
        x1 =1/(2*nScales) + (s-1)*1/nScales,
        y0 = 0.25, y1 = (s-1)-nScales, code = 0)
    graphics::arrows(
        x0 = 1/(2*nScales) + (s-1)*1/nScales, x1 = 1.1,
        y0 = (s-1)-nScales, y1 = (s-1)-nScales, code = 0)
    graphics::text(
        x = 1.1, y = (s-1)-nScales-0.25,
        labels = signif(minVal,2), adj = c(1,1), cex = 0.7)
    graphics::text(
        x = 1.5, y = (s-1)-nScales-0.25,
        labels = signif(midVal,2), adj = c(0.5,1), cex = 0.7)
    graphics::text(
        x = 1.9, y = (s-1)-nScales-0.25,
        labels = signif(maxVal,2), adj = c(0,1), cex = 0.7)
}


.legendSequential <- function(colorList, s){
    nScales <- length(colorList)
    width <- 1
