.legendQualitative <- function(colorList, s){
    nScales <- length(colorList)
    width <- 1
    height <- 0.5

    legend_text <- names(colorList[[s]]$Color)
    legend_col <- as.character(colorList[[s]]$Color)
    ncol <- length(legend_text)

    graphics::text(
        x = 1.5, y = (s-1)-nScales + 0.5*height,
        labels = colorList[[s]]$ScaleName, pos = 3, font = 2)
    graphics::legend(
        x = 1.1, y = (s-1)-nScales, adj = c(0,0.4),
        legend = legend_text, fill = legend_col, yjust = 0.5,
        bty = "n", pt.cex = min(c(3/(max(nchar(legend_text))/3), 2)),
        cex = min(c(2/(max(nchar(legend_text))/3),1)), ncol = 2,
        text.col = "black", horiz = FALSE)
    graphics::arrows(
        x0 = 1/(2*nScales) + (s-1)*1/nScales,
        x1 =1/(2*nScales) + (s-1)*1/nScales,
        y0 = 0.25, y1 = (s-1)-nScales, code = 0)
    graphics::arrows(
        x0 = 1/(2*nScales) + (s-1)*1/nScales, x1 = 1.1,
        y0 = (s-1)-nScales, y1 = (s-1)-nScales, code = 0)
}
